<old_str>FAR struct inode *inode_find(FAR const char *path, FAR const char **relpath)
{
  FAR struct inode *inode = g_root_inode;
  FAR const char *subpath;
  int ret;

  /* Get exclusive access to the inode tree */

  ret = inode_rlock();
  if (ret < 0)
    {
      return NULL;
    }

  /* Check if this is the root inode */

  if (!path || path[0] == '\0')
    {
      /* Return the root inode.  The root inode receives a reference
       * count for the lock that we set up above.  We don't need to
       * increment the reference count further.
       */

      inode_addref(inode);
      inode_runlock();
      *relpath = NULL;
      return inode;
    }

  /* Handle relative path differently */

  if (path[0] != '/')
    {
      /* Find the pseudo inode */

      inode = inode_search(&path);
      if (inode == NULL)
        {
          goto errout_with_lock;
        }

      /* Release the tree lock because the pseudo inode */

      inode_runlock();

      /* Dup the path to avoid to be released by inode_search */

      subpath = strdup(path);
      if (subpath == NULL)
        {
          /* Out of memory */

          return NULL;
        }

      /* Search from the pseudo inode */

      inode = inode_search(&subpath);
      if (inode == NULL)
        {
          /* Free the dupped path */

          lib_free((void *)subpath);
          return NULL;
        }

      *relpath = subpath;
      return inode;
    }

  /* Find the pseudo inode */

  inode = inode_search(&path);
  if (inode == NULL)
    {
      goto errout_with_lock;
    }

  /* Release the tree lock because the pseudo inode */

  inode_runlock();
  *relpath = path;
  return inode;

errout_with_lock:
  inode_runlock();
  return NULL;
}</old_str>
<new_str>FAR struct inode *inode_find(FAR const char *path, FAR const char **relpath)
{
  FAR struct inode *inode = g_root_inode;
  FAR const char *subpath;
  int ret;
  bool in_interrupt;

  /* Check if we're in interrupt context */

  in_interrupt = up_interrupt_context();

  /* Get exclusive access to the inode tree */

  if (in_interrupt)
    {
      /* In interrupt context, use non-blocking read lock */

      ret = inode_tryrlock();
      if (ret < 0)
        {
          /* Would block, return NULL */

          return NULL;
        }
    }
  else
    {
      /* In normal context, use blocking read lock */

      ret = inode_rlock();
      if (ret < 0)
        {
          return NULL;
        }
    }

  /* Check if this is the root inode */

  if (!path || path[0] == '\0')
    {
      /* Return the root inode.  The root inode receives a reference
       * count for the lock that we set up above.  We don't need to
       * increment the reference count further.
       */

      inode_addref(inode);
      inode_runlock();
      *relpath = NULL;
      return inode;
    }

  /* Handle relative path differently */

  if (path[0] != '/')
    {
      /* Find the pseudo inode */

      inode = inode_search(&path);
      if (inode == NULL)
        {
          goto errout_with_lock;
        }

      /* Release the tree lock because the pseudo inode */

      inode_runlock();

      /* Dup the path to avoid to be released by inode_search */

      subpath = strdup(path);
      if (subpath == NULL)
        {
          /* Out of memory */

          return NULL;
        }

      /* Search from the pseudo inode */

      inode = inode_search(&subpath);
      if (inode == NULL)
        {
          /* Free the dupped path */

          lib_free((void *)subpath);
          return NULL;
        }

      *relpath = subpath;
      return inode;
    }

  /* Find the pseudo inode */

  inode = inode_search(&path);
  if (inode == NULL)
    {
      goto errout_with_lock;
    }

  /* Release the tree lock because the pseudo inode */

  inode_runlock();
  *relpath = path;
  return inode;

errout_with_lock:
  inode_runlock();
  return NULL;
}</new_str>

